svg.script:
window.addEventListener('load', function() {
	const root = document.documentElement;
	const queryString = window.location.search;
	const urlParams = new URLSearchParams(queryString);

	// BEGIN AUDIO
	const context = new window.AudioContext();
	const now = function () { return context.currentTime };
	const osc = context.createOscillator();
	const gain = context.createGain();
	const smoothingInterval = 0.1;
	let oscStarted = false;

	// https://mynewmicrophone.com/fundamental-frequencies-of-musical-notes-in-a432-a440-hz/
	const scale = [
		261.63, // C4
		293.66, // D4
		329.63, // E4
		349.23, // F4
		392.00, // G4
		440.00, // A4
		493.88 // B4
	]

	gain.connect(context.destination);
	gain.gain.setValueAtTime(0, now());

	osc.frequency = 400;
	osc.connect(gain);
	// oscillator is started on first interaction, due to mobile safari 

	// END AUDIO

	const lettersTop = document.querySelectorAll('.top > *');

	for (const letter of lettersTop) {
		const randomDelay = Math.random() * (1.8 - 0.1) + 0.1;
		letter.style.animationDelay = randomDelay + 's';

		const newX = letter.getBBox().x + (letter.getBBox().width/2);
		const newY = letter.getBBox().y + (letter.getBBox().height/2);

		letter.style.transformOrigin = newX + 'px ' + newY + 'px';
	}

	const lettersBottom = document.querySelectorAll('.bottom > *');

	for (const letter of lettersBottom) {
		const randomDelay = (Math.random() * (1.8 - 0.1) + 0.1) + 0.35;
		letter.style.animationDelay = randomDelay + 's';

		const newX = letter.getBBox().x + (letter.getBBox().width/2);
		const newY = letter.getBBox().y + (letter.getBBox().height/2);

		letter.style.transformOrigin = newX + 'px ' + newY + 'px';
	}

	document.addEventListener('pointerdown', function (event) {
		if (event.target.classList.contains('letter')) {
			event.target.classList.add('highlight');

			event.target.style.animation = 'none';
			event.target.style.opacity = 1;

			if (!oscStarted) {
				osc.start(0);
				oscStarted = true;
			}

			const newFrequency = scale[parseInt(event.target.dataset.letterIndex)-1];
			osc.frequency.linearRampToValueAtTime(newFrequency, now());
			gain.gain.setTargetAtTime(1, now(), smoothingInterval);
		}
	});

	document.addEventListener('pointerup', function (event) {
		for (const letter of [...lettersTop].concat([...lettersBottom])) {
			letter.classList.remove('highlight');
		}
		gain.gain.setTargetAtTime(0, now(), smoothingInterval);
	});

	/*
	if (urlParams.get('color1')) {
		root.style.setProperty('--top-color', '#'+urlParams.get('color1'));
	}

	if (urlParams.get('color2')) {
		root.style.setProperty('--bottom-color', '#'+urlParams.get('color2'));
	}
	*/

},false);
